// Handle GET requests to /api/[shortId]
// Redirects to original URL or returns 404

const { resolveShortId } = require('../src/shorten.js')

/**
 * @param {import('vercel').VercelRequest} req
 * @param {import('vercel').VercelResponse} res
 */
module.exports = async (req, res) => {
	const shortId = req.query.shortId
	if (!shortId) {
		res.status(400).json({ error: 'Missing shortId' })
		return
	}

	const url = resolveShortId(shortId)
	if (url) {
		res.writeHead(302, { Location: url })
		res.end()
	} else {
		// Serve index.html with an invalid url message
		const fs = require('fs')
		const path = require('path')
		const indexPath = path.join(__dirname, '../public/index.html')
		let html = fs.readFileSync(indexPath, 'utf8')
		// Inject a message into the page (simple, non-intrusive)
		html = html.replace('<body>', '<body><div id="shorten-result" style="color:red;text-align:center;margin:1em;">Invalid or expired short URL.</div>')
		res.status(200).setHeader('Content-Type', 'text/html').end(html)
	}
}

// Handle POST requests to /api/shorten
// Expects JSON: { url: string }
// Returns: { shortUrl } or { error }

const { getShortUrl } = require('../src/shorten.js')

/**
 * @param {import('vercel').VercelRequest} req
 * @param {import('vercel').VercelResponse} res
 */
module.exports = async (req, res) => {
	if (req.method !== 'POST') {
		res.status(405).json({ error: 'Method Not Allowed' })
		return
	}

	let url
	try {
		url = req.body && req.body.url
		if (!url) throw new Error('Missing url')
	} catch (e) {
		res.status(400).json({ error: 'Invalid request body' })
		return
	}

	try {
		const shortUrl = getShortUrl(url)
		res.status(200).json({ shortUrl })
	} catch (e) {
		res.status(500).json({ error: e.message })
	}
}

// main.js - Handles frontend form and fetches short URL

/**
 * Initialize form event binding for URL shortener
 */
function initShortenForm() {
	const form = document.getElementById('shorten-form')
	const input = document.getElementById('url-input')
	let resultDiv = document.getElementById('shorten-result')
	if (!resultDiv) {
		resultDiv = document.createElement('div')
		resultDiv.id = 'shorten-result'
		form.insertAdjacentElement('afterend', resultDiv)
	}
	form.addEventListener('submit', async function (e) {
		e.preventDefault()
		const url = input.value.trim()
		resultDiv.textContent = ''
		if (!url) {
			resultDiv.textContent = 'Please enter a URL.'
			return
		}
		resultDiv.textContent = 'Shortening...'
		try {
			const resp = await fetch('/api/shorten', {
				method: 'POST',
				headers: { 'Content-Type': 'application/json' },
				body: JSON.stringify({ url })
			})
			const data = await resp.json()
			if (resp.ok && data.shortUrl) {
				resultDiv.innerHTML = `<a href="${data.shortUrl}" target="_blank" rel="noopener">${data.shortUrl}</a>`
			} else {
				resultDiv.textContent = data.error || 'Failed to shorten URL.'
			}
		} catch (err) {
			resultDiv.textContent = 'Error: ' + (err.message || err)
		}
	})
}

document.addEventListener('DOMContentLoaded', initShortenForm)

